// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.List;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.LmdbStore;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Differential tests for native evaluation of non-aggregate query roots: SELECT row streams with
 * Projection/Distinct/Reduced/Order/Slice wrappers over joins, OPTIONALs, UNIONs and MINUS. Every query is evaluated on
 * the native LMDB engine and on the generic evaluator and the results must match — order-sensitively for ORDER BY
 * queries with unique sort keys. Tests using assertNativeRows additionally require that the native compiler accepted
 * the query, so they fail while the feature is missing.
 */
public class LmdbNativeRowStreamTest {

	private static final String EX = "http://example.com/";
	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI type = vf.createIRI(EX, "type");
			IRI item = vf.createIRI(EX, "Item");
			IRI other = vf.createIRI(EX, "Other");
			IRI price = vf.createIRI(EX, "price");
			IRI name = vf.createIRI(EX, "name");
			IRI linked = vf.createIRI(EX, "linked");
			IRI sold = vf.createIRI(EX, "sold");
			for (int i = 0; i < 12; i++) {
				IRI subject = vf.createIRI(EX, "item" + i);
				conn.add(subject, type, item);
				// unique prices for deterministic ORDER BY
				conn.add(subject, price, vf.createLiteral(100 + i * 7));
				if (i % 2 == 0) {
					conn.add(subject, name, vf.createLiteral("item " + i));
				}
				if (i % 3 == 0) {
					conn.add(subject, linked, vf.createIRI(EX, "item" + ((i + 1) % 12)));
				}
				if (i % 4 == 0) {
					conn.add(subject, sold, vf.createLiteral(true));
				}
			}
			conn.add(vf.createIRI(EX, "otherA"), type, other);
			conn.add(vf.createIRI(EX, "otherA"), name, vf.createLiteral("other a"));
		}
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	private List<String> rows(String query, boolean sorted) {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			var stream = result.stream().map(LmdbNativeRowStreamTest::canonical);
			if (sorted) {
				stream = stream.sorted();
			}
			return stream.collect(Collectors.toList());
		}
	}

	/** Rows rendered independently of binding iteration order. */
	private static String canonical(BindingSet bindings) {
		return bindings.getBindingNames()
				.stream()
				.sorted()
				.filter(name -> bindings.getValue(name) != null)
				.map(name -> name + "=" + bindings.getValue(name))
				.collect(Collectors.joining(";", "[", "]"));
	}

	private void assertSameAsGeneric(String query, boolean orderSensitive) {
		List<String> nativeRows = rows(query, !orderSensitive);
		String previous = System.getProperty(NATIVE_FLAG);
		List<String> genericRows;
		try {
			System.setProperty(NATIVE_FLAG, "false");
			genericRows = rows(query, !orderSensitive);
		} finally {
			if (previous == null) {
				System.clearProperty(NATIVE_FLAG);
			} else {
				System.setProperty(NATIVE_FLAG, previous);
			}
		}
		assertThat(nativeRows).as("native vs generic for:\n" + query).isEqualTo(genericRows);
	}

	/** Asserts parity AND that the native compiler accepted the query root. */
	private void assertNativeRows(String query, boolean orderSensitive) {
		long before = LmdbNativeAggregateCompiler.COMPILED.get();
		assertSameAsGeneric(query, orderSensitive);
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("native row-stream compiler should accept:\n" + query)
				.isGreaterThan(before);
	}

	private static String q(String body) {
		return "PREFIX ex: <" + EX + ">\n" + body;
	}

	@Test
	public void plainSelectOverJoin() {
		assertNativeRows(q("SELECT ?s ?p WHERE { ?s ex:type ex:Item ; ex:price ?p }"), false);
	}

	@Test
	public void distinctOverOptional() {
		assertNativeRows(q("SELECT DISTINCT ?s ?n WHERE { ?s ex:type ex:Item . OPTIONAL { ?s ex:name ?n } }"),
				false);
	}

	@Test
	public void distinctNarrowProjectionOverWideOptionals() {
		// only ?s is projected: unprojected OPTIONAL branches must not affect the distinct row set
		assertNativeRows(q("SELECT DISTINCT ?s WHERE { ?s ex:type ex:Item . "
				+ "OPTIONAL { ?s ex:name ?n } OPTIONAL { ?s ex:linked ?l } }"), false);
	}

	@Test
	public void reducedProjection() {
		assertSameAsGeneric(q("SELECT REDUCED ?s WHERE { ?s ex:type ex:Item ; ex:price ?p }"), false);
	}

	@Test
	public void orderByAscending() {
		assertNativeRows(q("SELECT ?s ?p WHERE { ?s ex:type ex:Item ; ex:price ?p } ORDER BY ?p"), true);
	}

	@Test
	public void orderByDescendingWithLimit() {
		assertNativeRows(q("SELECT ?s ?p WHERE { ?s ex:type ex:Item ; ex:price ?p } ORDER BY DESC(?p) LIMIT 4"),
				true);
	}

	@Test
	public void orderByWithOffsetAndLimit() {
		assertNativeRows(
				q("SELECT ?s ?p WHERE { ?s ex:type ex:Item ; ex:price ?p } ORDER BY ?p OFFSET 3 LIMIT 5"),
				true);
	}

	@Test
	public void orderByOptionalVariable() {
		// unbound ?n rows must sort exactly like the generic evaluator sorts them
		assertNativeRows(q("SELECT ?s ?n WHERE { ?s ex:type ex:Item . OPTIONAL { ?s ex:name ?n } } "
				+ "ORDER BY ?n ?s"), true);
	}

	@Test
	public void orderByMultipleKeysMixedDirections() {
		assertNativeRows(q("SELECT ?s ?n ?p WHERE { ?s ex:type ex:Item ; ex:price ?p . "
				+ "OPTIONAL { ?s ex:name ?n } } ORDER BY ?n DESC(?p)"), true);
	}

	@Test
	public void limitWithoutOrder() {
		// row content is engine-dependent without ORDER BY; only the row count is comparable
		String query = q("SELECT ?s WHERE { ?s ex:type ex:Item } LIMIT 5");
		assertThat(rows(query, true)).hasSize(5);
	}

	@Test
	public void unionRoot() {
		assertNativeRows(q("SELECT DISTINCT ?s WHERE { { ?s ex:type ex:Item } UNION { ?s ex:type ex:Other } }"),
				false);
	}

	@Test
	public void minusRoot() {
		assertNativeRows(q("SELECT ?s WHERE { ?s ex:type ex:Item MINUS { ?s ex:sold true } }"), false);
	}

	@Test
	public void selectExpressionRename() {
		assertNativeRows(q("SELECT (?p AS ?cost) ?s WHERE { ?s ex:type ex:Item ; ex:price ?p } ORDER BY ?cost"),
				true);
	}

	@Test
	public void nestedOptionalsDenormalizedShape() {
		assertNativeRows(q("SELECT DISTINCT * WHERE { ?s ex:type ex:Item . "
				+ "OPTIONAL { ?s ex:name ?n . OPTIONAL { ?s ex:linked ?l } } "
				+ "OPTIONAL { ?s ex:sold ?sold } } ORDER BY ?s ?n"), true);
	}

	@Test
	public void filterWithGenericExpression() {
		assertNativeRows(q("SELECT ?s WHERE { ?s ex:type ex:Item ; ex:price ?p . "
				+ "FILTER(?p > 120 || CONTAINS(STR(?s), \"item1\")) }"), false);
	}

	@Test
	public void externalBindingConstrainsRows() {
		// evaluate with ?s pre-bound via a VALUES-free subselect join is covered elsewhere; here we check a
		// nested projection (subquery) — allowed to fall back, results must still match
		assertSameAsGeneric(q("SELECT ?s ?p WHERE { { SELECT ?s WHERE { ?s ex:type ex:Item } LIMIT 6 } "
				+ "?s ex:price ?p }"), false);
	}
}
